import { writeOutput } from "./codegen";

const DOCS_URL =
  "https://github.com/tiktok/tiktok-business-api-sdk/blob/main/js_sdk/docs/AuthenticationApi.md";
const PLACEHOLDER_VALUE =
  "act.CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocalCoffeeSafe";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from TikTok API for Business docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:tiktok-ads",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const tiktokAdsFirewall = {",
    '  name: "tiktok-ads",',
    '  description: "TikTok API for Business",',
    "  placeholders: {",
    `    TIKTOK_ADS_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://business-api.tiktok.com",',
    "      auth: {",
    "        headers: {",
    '          "Access-Token": "${{ secrets.TIKTOK_ADS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "    {",
    '      base: "https://sandbox-ads.tiktok.com",',
    "      auth: {",
    "        headers: {",
    '          "Access-Token": "${{ secrets.TIKTOK_ADS_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating TikTok Ads firewall config...");
  const ts = generateTypeScript();
  writeOutput("tiktok-ads", ts, import.meta.dirname);
}
